(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[1213],{9798:function(e,t,o){Promise.resolve().then(o.bind(o,3891))},3891:function(e,t,o){"use strict";o.r(t),o.d(t,{default:function(){return s}});var n=o(7437),a=o(4307);let i=[{id:"stage1",type:"label",text:"STAGE 1",subtext:"WARM UP THE LEAD",stage:"1",x:600,y:30,w:200,h:60},{id:"open",type:"talk",text:"\"Hey, is this [Name]?\n\nWhat's going on [Name]? This is [Rep] from Bronson's team here. I saw you applied to get started with AI ecom, is that correct?\"",subtext:"PACE (Danny 6/27): speed UP the first 10 sec but be crystal clear who/why/what — don't sound like every other cold caller or they tune out. PAIN is most important later: don't just chase goal-state — build the burning building (current situation → \"how's that affecting other areas of your life?\") then raise their vibrations.",x:460,y:120,w:480,h:110},{id:"interest",type:"talk",text:'"Awesome, we\'ll get you access to everything here in a sec. Just kinda walk me through, [Name] — what exactly got you interested in joining the free course and learning how to build an AI ecom brand?"',x:460,y:270,w:480,h:110},{id:"tonality_anchor",type:"alert",text:'⚠️ TONALITY — WHOLE CALL\nConcerned "homie" tone from the first hello. Curious, calm, like a friend — never salesy. Sound like a salesperson and they close up.',x:20,y:130,w:320,h:110},{id:"pace_anchor",type:"pace",text:"⚡ PACE — SPEED = AUTHORITY\nKeep it moving or they tune out / it feels like therapy. Fast + clear up top, keep the energy up. Slow down ONLY in the pain.",x:980,y:130,w:320,h:110},{id:"b2c_label",type:"branch",text:"ESCAPE THE MATRIX",subtext:"Making money, replace job, freedom, new income, side hustle",x:100,y:430,w:260,h:70},{id:"vague_label",type:"branch",text:"VAGUE / JUST LOOKING",subtext:"Just checking it out, not sure yet, looking for info",x:560,y:430,w:280,h:70},{id:"b2b_label",type:"branch",text:"B2B / SCALE BUSINESS",subtext:"Has a business, wants more clients, grow company",x:1040,y:430,w:260,h:70},{id:"b2c_q",type:"talk",text:"\"Ok, and I'm sure you're aware there's a lot of business models out there. I guess, what did you see in Bronson's content that made you feel like AI ecom would be the right fit for you?\"",x:30,y:550,w:400,h:110},{id:"b2c_outcome",type:"principle",text:"★ Get them to articulate WHY this business model. Their answer tells you how aware they are of what AI ecom actually is.",x:30,y:680,w:400,h:60},{id:"vague_q",type:"talk",text:"\"Got you. People typically request the free course for one of two reasons: they're either looking for another source of income, or they're already doing AI ecom and just looking to get to that next level. Which one of those boats do you feel like you're in personally?\"",x:460,y:550,w:480,h:130},{id:"vague_principle",type:"principle",text:'★ "Just looking for info" people don\'t buy. This question forces them to pick a lane. Whatever they pick, follow that path.',x:460,y:700,w:480,h:50},{id:"b2b_q",type:"talk",text:"\"Awesome, and I'm sure you're aware that there are a lot of tools and courses out there in this industry. I guess, what did you see in Bronson's content that made you want to apply to work with him specifically?\"",x:970,y:550,w:400,h:110},{id:"stage2",type:"label",text:"STAGE 2",subtext:"CURRENT STATE",stage:"2",x:600,y:820,w:200,h:60},{id:"current_q",type:"talk",text:'"Ok, well just so I could understand your current situation a little better — what exactly are you doing for work right now?"',x:460,y:910,w:480,h:90},{id:"no_job",type:"branch",text:"NO JOB",x:300,y:1050,w:160,h:50},{id:"has_job",type:"branch",text:"HAS A JOB",x:940,y:1050,w:160,h:50},{id:"no_job_q",type:"talk",text:'"Ok, and I guess what\'s the goal here with AI ecom? Are you hoping this could become your main source of income, or what does that look like?"',x:160,y:1130,w:440,h:90},{id:"has_job_q",type:"talk",text:'"Oh, you\'re doing [JOB]. And I guess, what would be the goal here with AI ecom? Are you hoping this could replace your [JOB], or what does that look like?"',x:800,y:1130,w:440,h:90},{id:"stage2_outcome",type:"principle",text:"★ We need to know: do they want to REPLACE their situation or ADD to it? This determines how deep we go on problem awareness.",x:460,y:1260,w:480,h:50},{id:"stage3",type:"label",text:"STAGE 3",subtext:"PROBLEM AWARENESS",stage:"3",x:570,y:1370,w:260,h:60},{id:"path1_label",type:"branch",text:'PATH 1: "YES, I WANT OUT"',subtext:"★ EASY",x:60,y:1480,w:300,h:60},{id:"path2_label",type:"branch",text:'PATH 2: "JOB\'S GOOD, JUST WANT X"',subtext:"★ MEDIUM",x:550,y:1480,w:300,h:60},{id:"path3_label",type:"branch",text:'PATH 3: "NOTHING WRONG, JUST LOOKING"',subtext:"★ HARDEST",x:1040,y:1480,w:300,h:60},{id:"p1_q1",type:"talk",text:'"Ok, and I guess — what\'s causing you to want to get out of your [JOB], bro?"',x:20,y:1580,w:380,h:70},{id:"p1_q2",type:"talk",text:'"And when you say [THEIR WORD] — can you give me an example? What\'s that actually look like day to day?"',x:20,y:1680,w:380,h:70},{id:"p1_see",type:"principle",text:'★ SEE: Get the specific event or reality they experience. "My back is messed up from lifting equipment."',x:20,y:1780,w:380,h:55},{id:"p1_feel_q",type:"talk",text:'"And what\'s that actually like to deal with day to day?"',subtext:'(Now go for the FEEL, not another example. Don\'t ask "what negative impact" — too salesy on low-ticket. Mirror their situation back and pull the emotion. Keep probing until you get how it actually feels.)',x:20,y:1860,w:380,h:120},{id:"p1_feel",type:"principle",text:'★ FEEL: Get the negative emotion. "I can\'t sleep, I never recover, I go right back to work."',x:20,y:2010,w:380,h:55},{id:"p2_q1",type:"talk",text:"\"Gotcha. I mean honestly, sounds like everything's going pretty good for you — so are you not able to make more money with what you're currently doing?\"",subtext:"Hold the same concerned homie tone as the whole call (see tonality anchor). Here it's a PUSH-AWAY: by acting like things sound fine for them, you make THEM argue why they're stuck. Push them away and they sell themselves on the problem.",x:510,y:1700,w:380,h:100},{id:"p2_clarify",type:"trigger",text:'CLARIFY VAGUE WORDS:\n• "capped" → "How do you mean?"\n• "freedom" → "What do you mean by that?"\n• "stuck" → "Give me an example?"\n• "limited" → "Limited in what way?"',x:510,y:1820,w:380,h:120},{id:"p2_number",type:"talk",text:"\"Oh okay — so the [JOB]'s going good for you? I guess, what does good actually look like for you? ...And how much are you making right now with that, if you don't mind me asking?\"",x:510,y:1580,w:380,h:80},{id:"p2_challenge",type:"talk",text:"\"I don't want to assume anything, but — what's wrong with making $[X]k a month? Is that not enough, or what's going on?\"",subtext:'ALT: "$7k is not bad. What makes you feel like it\'s not enough?"',x:510,y:1990,w:380,h:90},{id:"p2_deeper",type:"talk",text:'"And I guess, you\'re living check to check — is that causing any problems? What does that actually look like for you?"',x:510,y:2110,w:380,h:70},{id:"p2_note",type:"principle",text:'★ DON\'T say "what negative impact is that having on you" — too salesy for low-ticket. Keep it conversational.',x:510,y:2150,w:380,h:50},{id:"p3_q1",type:"talk",text:"\"Yeah, no, 100% — but I guess, what's kind of been going on at the job that's having you look into other things?\"",x:1e3,y:1580,w:380,h:80},{id:"p3_branch1",type:"branch",text:'"Not making enough"',subtext:"→ Goes to PATH 2",x:1e3,y:1700,w:180,h:60},{id:"p3_branch2",type:"branch",text:'"Job isn\'t it anymore"',subtext:"→ Goes to PATH 1",x:1200,y:1700,w:180,h:60},{id:"p3_still_vague",type:"branch",text:"STILL VAGUE",x:1100,y:1800,w:180,h:40},{id:"p3_q2",type:"talk",text:'"For sure — is there any particular reason why you\'re not able to [make more money / hit your goals] with your current job right now?"',x:1e3,y:1870,w:380,h:80},{id:"p3_principle",type:"principle",text:"★ You CANNOT move forward without a tangible problem. If they won't give one, they're not buying. Keep probing or recognize the tire-kicker and fast-track to the Base 44 pitch.",x:1e3,y:1980,w:380,h:85},{id:"stage4",type:"label",text:"STAGE 4",subtext:"SUMMARIZE + TRANSITION",stage:"4",x:570,y:2270,w:260,h:60},{id:"rule_donthave",type:"trigger",text:'THE "I DON\'T HAVE" RULE:\n\nNever finish with "I WANT." Always finish with "I DON\'T HAVE."\n\n❌ "So you want more freedom..."\n✅ "So you\'re not able to travel or help your family because you\'re capped at $7K..."\n\n"I want" is aspiration. "I don\'t have" is pain. Pain drives action.',x:100,y:2360,w:380,h:210},{id:"summarize_q",type:"talk",text:"\"Ok, so just to make sure I understand — you want to be able to [THEIR SPECIFIC DESIRE], but right now you're in [THEIR SITUATION] because of [WHAT THEY DON'T HAVE]. Is that correct?\"",x:510,y:2370,w:480,h:100},{id:"income_nojob_main",type:"talk",text:'"Ok, and for you personally, how much money would you need to be making per month in order for this to be your main source of income?"',x:30,y:2510,w:320,h:115},{id:"income_job_replace",type:"talk",text:'"Ok, and for you personally, how much money would you need to be making per month in order to fully replace your [JOB] job?"',x:430,y:2510,w:320,h:115},{id:"income_job_side",type:"talk",text:'"Ok, and for you personally, how much money would you need to be making per month in order for this to be a solid side hustle for yourself?"',subtext:"⚠️ EXCEPTION ONLY — use the side-hustle framing if their job/life is already going GOOD and they just wanna ADD income on top. If they need this to CHANGE their situation, push REPLACE — don't hand them the low-commitment side-hustle out.",x:830,y:2510,w:320,h:165},{id:"fivek_challenge",type:"talk",text:'"$5k! What makes you say $5k specifically? How would that change things for you?"',subtext:"(Repeat back their exact number. Challenge it. Get them to paint the picture.)",x:460,y:2660,w:480,h:85},{id:"stage5",type:"label",text:"STAGE 5",subtext:"FINANCIAL QUALIFYING",stage:"5",x:570,y:2790,w:260,h:60},{id:"fq_warning",type:"trigger",text:"⚠️ LONGER YOU STAY = WORSE\n\nEvery extra second raises their guard — feels like an interrogation, YOU end up on the hot seat. Qualify properly but FAST. Only true DQ = < $50; everyone else, sell the appointment.",x:20,y:2860,w:340,h:120},{id:"fq_question",type:"talk",text:"\"Ok, and if we could help you [STATED GOALS]... I'm sure you're aware, just like any other business model, when it comes to e-commerce there's some startup capital involved. Just so we know what sort of strategies we can use in your case — how much capital do you have set aside at the moment to get the business up and running?\"",x:420,y:2880,w:520,h:130},{id:"fq_quals",type:"trigger",text:"HT QUALIFICATIONS:\n• $2k liquid\n  — OR —\n• Minimum $4k credit limit\n  — OR —\n• 500+ credit score, 21+ and $500 Budget",x:1e3,y:2880,w:300,h:145},{id:"fq_broke",type:"alert",text:"< $50 / Broke",subtext:"Literally cannot afford $50",x:1100,y:3240,w:200,h:65},{id:"fq_broke_dq",type:"alert",text:"TRUE DQ\n\n\"No worries at all bro. Go through the free course — it's yours regardless. When you're in a position to invest, hit us up.\"",x:1080,y:3330,w:240,h:120},{id:"fq_ez",type:"principle",text:"*EZ Qualified*",subtext:"I have x amount set aside to invest!\n($ is enough)",x:80,y:3060,w:220,h:80},{id:"fq_iffy",type:"principle",text:"*iffy Qualified*",subtext:"$ is enough but..\n- might\n- maybe\n- potentially\n- *prospect sounds unsure",x:380,y:3060,w:260,h:110},{id:"fq_budget_low",type:"branch",text:'"Budget too low"',subtext:"Has some capital but below HT quals\n(more than $50, under $2k liquid)",x:800,y:3060,w:220,h:80},{id:"fq_iffy_confirm",type:"talk",text:'"Ok, that is something we could work with, but again, if we could help you [STATED GOALS], is that [THEIR BUDGET] something you have now and would be willing to allocate if everything makes sense?"',x:310,y:3220,w:380,h:130},{id:"fq_iffy_yes",type:"principle",text:"yes",x:370,y:3390,w:100,h:40},{id:"fq_iffy_no",type:"alert",text:"no",x:530,y:3390,w:100,h:40},{id:"fq_iffy_notht",type:"alert",text:"Not HT Qualified",subtext:"→ Base44 only",x:490,y:3460,w:180,h:55},{id:"fq_bt_talk",type:"talk",text:"\"That's awesome! There's definitely a way you could get the business going. Just to see what sort of strategies we could use in your case, what's your age and do you have a credit card?\"",x:740,y:3200,w:340,h:140},{id:"fq_bt_tonality",type:"principle",text:'"Not a big deal" tonality',x:680,y:3360,w:200,h:40},{id:"fq_bt_21",type:"principle",text:"21+ and has credit card",x:700,y:3410,w:190,h:40},{id:"fq_bt_under21",type:"alert",text:"under 21 y/o or has no credit",x:1050,y:3500,w:210,h:45},{id:"fq_bt_under21_notht",type:"alert",text:"Not HT Qualified",subtext:"→ Base44 only",x:1050,y:3570,w:180,h:55},{id:"fq_bt_cc_limit",type:"talk",text:'"ok what\'s the available limit on that credit card, just to see what strategies we can use?"',x:670,y:3480,w:260,h:90},{id:"fq_bt_pif",type:"principle",text:"Hard cash + credit limit = PIF",x:630,y:3600,w:230,h:45},{id:"fq_bt_less_pif",type:"branch",text:"21y/o+ & Hard cash + credit limit = less than pif",x:890,y:3600,w:280,h:50},{id:"fq_bt_credit_score",type:"talk",text:'"ok, and whats your credit score?"',x:910,y:3680,w:240,h:55},{id:"fq_bt_us_note",type:"trigger",text:"*US Based only, if not international, budget dq*",x:910,y:3740,w:240,h:50},{id:"fq_bt_500plus",type:"principle",text:"500+ with at least $500 hard cash",x:810,y:3810,w:260,h:50},{id:"fq_bt_below500",type:"alert",text:"below 500 and/or has less than $500 hard cash",x:1110,y:3810,w:260,h:70},{id:"fq_bt_no",type:"alert",text:"no",x:1170,y:3890,w:100,h:35},{id:"fq_bt_credit_usage",type:"talk",text:'"awesome and have you used your credit for anything in the 4 figure range like student loans or car loan?"',x:850,y:3940,w:280,h:110},{id:"fq_bt_credit_yes",type:"principle",text:"yes",x:750,y:4080,w:100,h:40},{id:"fq_bt_credit_no",type:"alert",text:"no",x:1050,y:4080,w:100,h:40},{id:"fq_bt_credit_notht",type:"alert",text:"Not HT Qualified",subtext:"→ Base44 only",x:1010,y:4140,w:180,h:55},{id:"stage6",type:"label",text:"STAGE 6",subtext:"SELL THE NEED",stage:"6",x:300,y:4170,w:200,h:60},{id:"knowledge_check",type:"talk",text:"\"Ok and it really doesn't make much difference, but just to see where you're at — what do you know about our business model so far in terms of how it works and how you actually make money with it?\"",subtext:"(If they know nothing → give 30-sec explanation below. If they get it → skip to help question.)",x:200,y:4270,w:480,h:130},{id:"knowledge_explain",type:"talk",text:"\"So basically the business model is AI ecom — you're building a real e-commerce brand — not a generic pump-and-dump store. You pick one product in an evergreen niche like health, supplements, pets, or beauty, build a real brand around it, scale it, and eventually sell it for a big payday. You're building a sellable asset. Does that make sense?\"",subtext:"(Only if they didn't know. Keep it to 30 seconds max.)",x:750,y:4270,w:350,h:150},{id:"help_question",type:"talk",text:'"Awesome. So I guess based off that, what part of the business do you feel like you need the most help in? Would it be picking the right product, building the brand, or scaling with ads?"',x:200,y:4545,w:480,h:80},{id:"why_help",type:"talk",text:'"And why do you feel you would need the most help with that specifically?"',subtext:"(Their answer = the exact need you summarize back in the pitch.)",x:200,y:4655,w:480,h:75},{id:"summarize_need",type:"talk",text:'"Ok, so it sounds like for you it\'s really just having a clear A-to-Z road map on how to [THEIR SPECIFIC NEED — e.g. acquire clients / run ads / get started]. Is that fair to say?"',subtext:"(Get a YES before moving to the pitch. This is the need you sell to.)",x:200,y:4760,w:480,h:100},{id:"stage7",type:"label",text:"STAGE 7",subtext:"PITCH",stage:"7",x:300,y:4905,w:200,h:60},{id:"pitch_steps",type:"trigger",text:"PITCH SEQUENCE:\n\n1. Recommend for course → bridge to Base44\n2. Get buy-in on the course\n3. Get buy-in on Base44\n4. Get buy-in on commitment\n5. Price drop → ask for the sale",x:200,y:4995,w:480,h:135},{id:"pitch_bridge",type:"talk",text:'"So next step from here would be to get you set up with the free course that you signed up for. Have you ever applied for Bronson\'s program in the past?"',subtext:"(Yes or no doesn't matter — either way, transition to the price reveal below.)",x:200,y:5165,w:480,h:110},{id:"pitch_reveal",type:"talk",text:"\"OK, well, I'm not sure you're aware of this, but the course that we're giving to you for free used to be anywhere between $2,000 and $5,000 USD. Now we're actually able to give this away for free because we partnered with a major AI company called Base 44. Have you heard of Base 44 before or no?\"",x:200,y:5305,w:480,h:110},{id:"pitch_base44_explain",type:"talk",text:"\"So here's how it actually works.\n\nMost people who try ecom go about it all wrong — they test random product after random product, run a few stores at once, throw money at ads hopin somethin sticks, and burn more than they make back. 'Cause generic dropshipping's built to fail: no brand, no repeat customers, nothin you actually own. You're rentin a store, not buildin a business. Make sense why most people quit before they ever make a dollar?\n\nWhat we do's different. Instead of guessin on a product, we use AI to research what's actually got demand — real buyers, real search — so you start on somethin proven instead of throwin darts. That alone saves you months of testin and a ton of wasted ad spend.\n\nThen we point you to vetted suppliers, so you're not diggin through a hundred random ones hopin the quality's there. You skip the sourcing headache that stops most beginners before they even start.\n\nAnd from there the AI helps at every step — findin the product, the ad copy, buildin out the brand and the store — so you move faster and cheaper than the old-school way. You don't gotta be techy, you don't need a big team, you're not figurin it out alone.\n\nAnd the whole point? You're not spinnin up a throwaway store — you're buildin a real brand. Real customers that come back, somethin that's actually yours. Not a get-rich-quick thing — a real business, done the smart way.\n\nFrom what we just went over — what part of that feels the most valuable to you?\"",subtext:'(Grounded — no "sell for millions" / no guaranteed outcomes. Contrast (why dropshipping fails) → AI research + vetted suppliers + tools → real brand → open tie-down. Two check-ins built in. CONFIRM W/ KAUA: exact Base 44 capabilities.)',x:200,y:5445,w:480,h:520},{id:"pitch_45sec_rule",type:"principle",text:"★ 45-SECOND RULE: Never go 45 seconds in a pitch without checking in on the prospect or getting a tie-down. This should be a collaborative pitch, not you talking for 3 minutes while they say nothing.",x:750,y:5445,w:380,h:90},{id:"pitch_buyin_base44",type:"talk",text:'"Do you actually feel like Base 44 and all the tools would help you build a real brand you could actually scale? Like, do you feel this can genuinely get you there?"',subtext:"(Wait for YES.)",x:200,y:6155,w:480,h:115},{id:"pitch_commitment",type:"talk",text:"\"Awesome, well listen man — I would definitely recommend you inside the course. I'm gonna walk you through how we're gonna get started. We always want to make sure you guys actually get results, because none of this is gonna work unless you actually do what's inside. So I guess, today, are you actually committed to take action on this so that you can [THEIR DREAM OUTCOME]?\"",subtext:"\"The only reason why I ask this is because a lot of people say they're committed, but then they'll just get inside and they don't do anything.\"",x:200,y:6295,w:480,h:150},{id:"pitch_commitment_why",type:"talk",text:"\"We've worked with a lot of people, [Name]. We only want to give this to people that are actually going to use it. So I guess — why do you feel like you're committed?\n\nBecause this is a free course and the software is very cheap, so there's really not much commitment. Some people just put it on the sideline. Why is it important for you to come in and actually do this today?\"",subtext:"(Free + cheap = low commitment frame. Makes them sell themselves on why THEY are different from the people who don't take action.)",x:200,y:6475,w:480,h:160},{id:"pitch_price",type:"talk",text:"\"The only reason I can give you this whole course for free — the same one Bronson charged $3,000 for — is because of his direct partnership with Base 44 and Wix. You get the full A-Z course free as long as you're an active subscriber on their platforms. So you're not paying for a course, you're just covering the tools you'd need to build the brand anyway. [CONFIRM EXACT BASE 44 + WIX SUB COST] Which works better for you — paying yearly or monthly?\"",subtext:"(Partnership frame — they're not buying software, they're maintaining access to the free program through a subscription.)",x:200,y:6665,w:480,h:290},{id:"pitch_close",type:"talk",text:'"Based off of those two, which one makes the most sense for you at this point? Would it be the $192 or the $50 a month?"',subtext:"(Shut up. Wait for the answer. Do NOT fill the silence.)",x:200,y:6985,w:480,h:90},{id:"pitch_objections",type:"trigger",text:'COMMON OBJECTIONS:\n\n• "I want to try the course first" →\n"The course tells you what to do. Base 44 does it. Lock in the $50 now so it\'s there when you\'re ready."\n\n• "I need to think about it" →\n"What\'s the hesitation — the software itself or the $50?" Then handle.\n\n• "I can\'t afford it right now" →\n"Can you do $50 today?" If no → let them go gracefully.\n\n• "Is there a catch?" →\n"No catch. Base 44 sponsors the course because they want people using their software. You keep access as long as your subscription is active."',x:750,y:6295,w:380,h:300},{id:"stage8",type:"label",text:"STAGE 8",subtext:"ONBOARDING",stage:"8",x:300,y:7155,w:200,h:60},{id:"onboard_steps",type:"trigger",text:"ON-CALL ONBOARDING:\n\n1. Cookie check → incognito if needed\n2. Send Base44 signup link via text\n3. Toggle to Monthly → select Builder ($50) or Annual ($192)\n4. Create account (confirm email on file)\n5. Authorization code → payment → subscribe\n6. Navigate to billing → screenshot → send to your personal #\n7. Send screenshot to team → get activation link\n8. Send activation link → create Bronson account\n9. Confirm they see phases 1-6 → wrap up",x:200,y:7245,w:480,h:210},{id:"onboard_cookie",type:"talk",text:'"So have you ever opened the Base 44 website before, or no?"',x:200,y:7485,w:480,h:50},{id:"onboard_cookie_yes",type:"branch",text:"Yes / Not sure",x:200,y:7560,w:170,h:40},{id:"onboard_cookie_no",type:"branch",text:"No, never",subtext:"→ Skip incognito",x:500,y:7560,w:170,h:50},{id:"onboard_incognito",type:"talk",text:"\"No worries. Just because sometimes with the cookies and stuff — it's kinda hard to explain but just to make sure everything goes through smoothly and there's no glitches, can you go on a private browser or incognito mode?\n\nWhether that's Google incognito mode or Safari private browser, just make sure you're on there. Does that work?\"",subtext:'(If they can\'t find incognito: "It might be a three-line button or a profile picture button in the top right of your browser.")',x:200,y:7625,w:480,h:160},{id:"onboard_cookie_note",type:"principle",text:"★ AFFILIATE COOKIES: If they've visited Base44 before, old cookies can mess up our affiliate tracking and we won't get paid. Incognito = clean session = affiliate credit. If they've NEVER been on the site, skip this step.",x:750,y:7485,w:380,h:100},{id:"onboard_send_link",type:"talk",text:'"So what I can do is send you a link to your phone number here. We can walk through the steps to get set up on Base 44, and then once we make that happen, I\'ll get you set up on the Bronson program as well. Does that sound good?"\n\n"So I\'ll send that over to your phone number right now. Let me know when that link comes through and I can walk you through the steps."',subtext:"(Wait for them to confirm they received the text.)",x:200,y:7815,w:480,h:160},{id:"onboard_navigate",type:"talk",text:"\"Once you see that link there, go ahead and click on it — it's gonna take you to the Base 44 homepage. It says 'Plans from First Idea to Full Scale.'\n\nUnderneath those words, you're gonna see a Yearly option that says 'save 20%' in parenthesis, and then there's a Monthly option. Since you wanna go with the [monthly/annual], go ahead and toggle over to that option. Do you see that?\"\n\n\"So with the [monthly/annual], we're gonna do the Builder [for $50 / for $192]. Go ahead and click on the Get Started button underneath it.\"",subtext:"(Starter plan won't work — no credits, no integrations. Must be Builder.)",x:200,y:8005,w:480,h:200},{id:"onboard_account",type:"talk",text:"\"Once you click Get Started, it's gonna have you create an account with Base 44 if you don't have one already. So you'll put in your email, create a password.\n\nAnd just to confirm — the email I have for you on file is [THEIR EMAIL]. Go ahead and use that email to create your account there.\n\nLet me know when the account is created — you'll land on a new page that says 'Choose the plan that's right for you.'\"",x:200,y:8235,w:480,h:185},{id:"onboard_payment",type:"talk",text:"\"Go ahead and click on the Get Builder button. Make sure you're on the [monthly/yearly] option, then press Continue to Checkout down at the bottom.\n\nIt's gonna send you an authorization code to your phone number just to confirm it's you. Once you put that code in, it'll take you to where you can put in the payment details — card info, Apple Pay, whatever works.\n\nOnce you do that, hit the Subscribe button. Let me know when the payment goes through because I'll need a couple confirmation things from you so I can get you set up for the Bronson program.\"",x:200,y:8455,w:480,h:200},{id:"onboard_screenshot",type:"talk",text:"\"Ok perfect. So now do you see up in the top left corner — it's gonna say [Name]'s Workspace? Go ahead and click on that.\n\nIt's gonna give you a dropdown that says Settings. Click on Settings.\n\nAnd then once you're inside there, click on Plan and Billing.\n\nUnder the Billing History, it's gonna show you the plan you signed up for, the date of purchase, things like that. I'll just need a screenshot of that section there.\"",subtext:'(ALT NAV — some users see it differently: "Bottom left of your screen, there\'s a little profile picture. Click on that → Account Settings → Plan and Billing.")',x:200,y:8685,w:480,h:220},{id:"onboard_send_screenshot",type:"talk",text:"\"My number is gonna be [YOUR PERSONAL NUMBER]. That's my personal right there. Go ahead and send the picture over there.\n\nOnce I get the picture on my end, I'll send it directly to the team, and then they'll get me an activation link to get you set up on Bronson. It should only be a few seconds.\"",subtext:'(If screenshot won\'t deliver — international: "Do you have WhatsApp? Send it on WhatsApp, same number.")',x:200,y:8935,w:480,h:155},{id:"onboard_activation",type:"talk",text:"\"Alright, I'm gonna send the activation link to your phone number now. Once it comes through, click on that link.\n\nYou'll wanna create an account with Bronson — put in your email, create a passcode. And then you should have access to the course with all the modules and phases.\"",subtext:'(If it says "Sign in link expired": "No worries — just put in your email again, press Continue, and they\'ll send a new link to your email. Check your inbox.")',x:200,y:9120,w:480,h:165},{id:"onboard_confirm",type:"talk",text:"\"So you see phases 1 through 6? Those are all the steps to follow through. You're gonna wanna go in order — it won't let you skip around. You'll have to finish phase 1 to unlock phase 2, so on and so forth.\n\nIf you have any questions, you have both my numbers — my work phone and my personal. You can always reach out if you need something. But other than that, you have everything you need to get the business up and rolling.\"",x:200,y:9315,w:480,h:165},{id:"onboard_troubleshoot",type:"trigger",text:'TROUBLESHOOTING:\n\n• Can\'t find incognito → "Three-line menu button or profile picture in top right of browser"\n\n• Screenshot not delivering → "Do you have WhatsApp? Send it there, same number"\n\n• Activation link expired → "Put your email in again, press Continue, check your inbox for a new link"\n\n• Stuck on plan page → "Make sure you toggled to [Monthly/Yearly] first, then click Builder"\n\n• Can\'t find billing → Try both: "Top left [Name]\'s Workspace" OR "Bottom left profile picture → Account Settings"',x:750,y:8005,w:380,h:300},{id:"stage9",type:"label",text:"STAGE 9",subtext:"SELL THE NEED FOR HT",stage:"9",x:290,y:9575,w:260,h:60},{id:"ht_check",type:"branch",text:"Is this lead HT Qualified?",subtext:"(from Stage 5 FQ tagging)",x:300,y:9665,w:280,h:65},{id:"not_ht_goodbye",type:"branch",text:"NOT HT Qualified",subtext:"→ Wrap up the call",x:60,y:9795,w:200,h:60},{id:"goodbye_talk",type:"talk",text:"\"Alright [Name], you're all set bro. You've got the course, you've got Base 44. Go through the modules, start applying what you learn, and if you run into anything — you have my number. Just shoot me a text. Sound good?\"",subtext:"(Keep it short. They already bought.)",x:10,y:9885,w:320,h:140},{id:"goodbye_end",type:"principle",text:"★ END CALL. Fill out EOC report immediately.",x:10,y:10055,w:320,h:40},{id:"ht_qualified",type:"branch",text:"HT Qualified",subtext:"→ Sell the need for high ticket",x:560,y:9795,w:220,h:60},{id:"ht_bait",type:"talk",text:"\"Alright [Name], how are you feeling? Awesome!\n\nWell listen bro, the only reason why we're able to actually maintain the success rate we do have in the program is because we're very intentional about the type of support and guidance we can give you guys.\"",subtext:"(Pre-frame only. Don't ask about past struggles — flow straight into the support question.)",x:450,y:9895,w:480,h:150},{id:"ht_bait_note",type:"trigger",text:"WHY SIMPLIFIED:\n\nRemoved past-struggle question. The pre-frame alone is enough to set up the support question. The propose box already ties back to their discovery pain — we don't need a separate anchor from a past-struggle question.",x:970,y:9895,w:340,h:120},{id:"ht_support",type:"talk",text:'"Are you the type of person that needs coaching calls, direct support and guidance from Bronson and the team, pretty much just more one-on-one support in general?\n\nOr what can we do to increase the probability of you succeeding in this business and ultimately getting to [DREAM OUTCOME]?"',subtext:'(Wait for answer) → "Ok, and why do you feel like having [WHAT THEY SAID] would increase the probability of you getting to [DREAM OUTCOME]?"',x:450,y:10075,w:480,h:165},{id:"ht_doubt",type:"talk",text:'"I mean [Name], you are in the free course right now. You could technically watch the videos and do this all by yourself.\n\nWhat do you feel like you would get from having direct guidance and support from Bronson and the team that you couldn\'t get just doing it all alone?"',subtext:"(They sell themselves on needing more. Whatever they say here, you use in the propose.)",x:450,y:10370,w:480,h:150},{id:"ht_doubt_note",type:"principle",text:"★ DOUBT THE FREE COURSE: Don't tell them the course isn't enough — make THEM say it. They verbalize the gap between self-paced and supported. That's the need you sell to.",x:970,y:10370,w:340,h:80},{id:"ht_propose",type:"talk",text:"\"Ok listen [Name], I know you're already in the free course. And I know you said you would need more help — coaching calls, one-on-one support — because you struggled with [THEIR PAST STRUGGLE] when trying to do something like this before, right? And your biggest goal is still to get to [THEIR DREAM OUTCOME], correct?\n\nSo here's the thing bro — we just gave you the free course, but the free course is just videos. There's not one-on-one support, coaching calls — I mean it's great, but it doesn't come with what you're saying you need.\n\nNow I only work here in the getting-started side, so when it comes to actually getting more advanced one-on-one support, I would need to connect you with one of the head coaches that works directly with Bronson. I can call Bronson and see if we could get you that additional support — I'm not sure if he could, but that coach can sit down with you and figure out if we could actually get you [THEIR SUPPORT NEED] so you can [DREAM OUTCOME].\n\nWhat time today would you be sitting at your desk, ready to meet with that coach to see if we could get you the one-on-one support?\"",subtext:"(Shut up. Wait for the time. If they give you a time → Stage 10.)",x:450,y:10550,w:480,h:370},{id:"ht_propose_note",type:"trigger",text:'THREE FRAMES IN ONE:\n\n1. DEPARTMENT FRAME: "I only work here in the getting-started side" — makes it clear this is a DIFFERENT call with a DIFFERENT person. Prevents lead from thinking the closer call is just onboarding part 2.\n\n2. SCARCITY + FAVOR: "I can call Bronson and see if we could get you that" — you\'re doing them a favor, not selling. "I\'m not sure if he could" = scarcity.\n\n3. CLEAR EXPECTATION: "That coach can sit down with you and figure out..." — they know exactly what the call is about. No bait-and-switch.',x:970,y:10550,w:340,h:260},{id:"stage10",type:"label",text:"STAGE 10",subtext:"SOLIDIFY THE UPSELL",stage:"10",x:530,y:11015,w:260,h:60},{id:"solidify_steps",type:"trigger",text:'SOLIDIFY THE BOOKING:\n\n1. Confirm date/time of upsell call\n2. Set expectations — what the call will cover\n3. Get verbal commitment to show up\n4. "If something comes up, just text me — don\'t ghost"\n5. Send calendar invite',x:460,y:11105,w:400,h:160},{id:"solidify_talk",type:"talk",text:"[SOLIDIFICATION WORD TRACKS TBD]",x:460,y:11295,w:400,h:45},{id:"solidify_end",type:"principle",text:"★ END CALL. Fill out EOC report immediately. Tag contact as HT-booked in GHL.",x:460,y:11365,w:400,h:50}],r=[{from:"open",to:"interest"},{from:"interest",to:"b2c_label"},{from:"interest",to:"vague_label"},{from:"interest",to:"b2b_label"},{from:"b2c_label",to:"b2c_q"},{from:"vague_label",to:"vague_q"},{from:"b2b_label",to:"b2b_q"},{from:"b2c_q",to:"current_q",label:""},{from:"b2b_q",to:"current_q",label:""},{from:"current_q",to:"no_job"},{from:"current_q",to:"has_job"},{from:"no_job",to:"no_job_q"},{from:"has_job",to:"has_job_q"},{from:"stage3",to:"path1_label"},{from:"stage3",to:"path2_label"},{from:"stage3",to:"path3_label"},{from:"path1_label",to:"p1_q1"},{from:"p1_q1",to:"p1_q2"},{from:"p1_q2",to:"p1_see"},{from:"p1_see",to:"p1_feel_q"},{from:"p1_feel_q",to:"p1_feel"},{from:"path2_label",to:"p2_number"},{from:"p2_number",to:"p2_q1"},{from:"p2_q1",to:"p2_clarify"},{from:"p2_clarify",to:"p2_challenge"},{from:"p2_challenge",to:"p2_deeper"},{from:"path3_label",to:"p3_q1"},{from:"p3_q1",to:"p3_branch1"},{from:"p3_q1",to:"p3_branch2"},{from:"p3_still_vague",to:"p3_q2"},{from:"summarize_q",to:"income_nojob_main",label:"No job → main"},{from:"summarize_q",to:"income_job_replace",label:"Has job → replace"},{from:"summarize_q",to:"income_job_side",label:"ONLY if comfortable → side"},{from:"income_nojob_main",to:"fivek_challenge"},{from:"income_job_replace",to:"fivek_challenge"},{from:"income_job_side",to:"fivek_challenge"},{from:"fivek_challenge",to:"fq_question"},{from:"fq_question",to:"fq_ez",label:"EZ Qualified"},{from:"fq_question",to:"fq_iffy",label:"Iffy Qualified"},{from:"fq_question",to:"fq_budget_low",label:"Budget too low for HT"},{from:"fq_question",to:"fq_broke",label:"< $50"},{from:"fq_broke",to:"fq_broke_dq"},{from:"fq_ez",to:"knowledge_check"},{from:"fq_iffy",to:"fq_iffy_confirm"},{from:"fq_iffy_confirm",to:"fq_iffy_yes"},{from:"fq_iffy_confirm",to:"fq_iffy_no"},{from:"fq_iffy_yes",to:"knowledge_check"},{from:"fq_iffy_no",to:"fq_iffy_notht"},{from:"fq_iffy_notht",to:"knowledge_check"},{from:"fq_budget_low",to:"fq_bt_talk"},{from:"fq_bt_talk",to:"fq_bt_21"},{from:"fq_bt_talk",to:"fq_bt_under21"},{from:"fq_bt_under21",to:"fq_bt_under21_notht"},{from:"fq_bt_under21_notht",to:"knowledge_check"},{from:"fq_bt_21",to:"fq_bt_cc_limit"},{from:"fq_bt_cc_limit",to:"fq_bt_pif"},{from:"fq_bt_cc_limit",to:"fq_bt_less_pif"},{from:"fq_bt_pif",to:"knowledge_check"},{from:"fq_bt_less_pif",to:"fq_bt_credit_score"},{from:"fq_bt_credit_score",to:"fq_bt_500plus"},{from:"fq_bt_credit_score",to:"fq_bt_below500"},{from:"fq_bt_500plus",to:"fq_bt_credit_usage"},{from:"fq_bt_below500",to:"fq_bt_no"},{from:"fq_bt_no",to:"fq_bt_credit_usage"},{from:"fq_bt_credit_usage",to:"fq_bt_credit_yes"},{from:"fq_bt_credit_usage",to:"fq_bt_credit_no"},{from:"fq_bt_credit_no",to:"fq_bt_credit_notht"},{from:"fq_bt_credit_notht",to:"knowledge_check"},{from:"fq_bt_credit_yes",to:"knowledge_check"},{from:"knowledge_check",to:"knowledge_explain",label:"Don't know"},{from:"knowledge_check",to:"help_question"},{from:"knowledge_explain",to:"help_question"},{from:"help_question",to:"why_help"},{from:"why_help",to:"summarize_need"},{from:"summarize_need",to:"pitch_steps"},{from:"pitch_steps",to:"pitch_bridge"},{from:"pitch_bridge",to:"pitch_reveal"},{from:"pitch_reveal",to:"pitch_base44_explain"},{from:"pitch_base44_explain",to:"pitch_buyin_base44"},{from:"pitch_buyin_base44",to:"pitch_commitment"},{from:"pitch_commitment",to:"pitch_commitment_why"},{from:"pitch_commitment_why",to:"pitch_price"},{from:"pitch_price",to:"pitch_close"},{from:"pitch_close",to:"onboard_steps"},{from:"onboard_steps",to:"onboard_cookie"},{from:"onboard_cookie",to:"onboard_cookie_yes",label:"Yes"},{from:"onboard_cookie",to:"onboard_cookie_no",label:"No"},{from:"onboard_cookie_yes",to:"onboard_incognito"},{from:"onboard_incognito",to:"onboard_send_link"},{from:"onboard_cookie_no",to:"onboard_send_link"},{from:"onboard_send_link",to:"onboard_navigate"},{from:"onboard_navigate",to:"onboard_account"},{from:"onboard_account",to:"onboard_payment"},{from:"onboard_payment",to:"onboard_screenshot"},{from:"onboard_screenshot",to:"onboard_send_screenshot"},{from:"onboard_send_screenshot",to:"onboard_activation"},{from:"onboard_activation",to:"onboard_confirm"},{from:"onboard_confirm",to:"ht_check"},{from:"ht_check",to:"not_ht_goodbye",label:"No"},{from:"ht_check",to:"ht_qualified",label:"Yes"},{from:"not_ht_goodbye",to:"goodbye_talk"},{from:"goodbye_talk",to:"goodbye_end"},{from:"ht_qualified",to:"ht_bait"},{from:"ht_bait",to:"ht_support"},{from:"ht_support",to:"ht_doubt"},{from:"ht_doubt",to:"ht_propose"},{from:"ht_propose",to:"solidify_steps"},{from:"solidify_steps",to:"solidify_talk"},{from:"solidify_talk",to:"solidify_end"}];function s(){return(0,n.jsx)(a.Z,{scriptId:"bronson-script",badge:"B",title:"Bronson — Sales Script",subtitle:"Phase 1: Discovery + Problem Awareness",defaultNodes:i,defaultEdges:r})}}},function(e){e.O(0,[4307,2971,2117,1744],function(){return e(e.s=9798)}),_N_E=e.O()}]);